Question: How many consecutive days did A4F_44160's {minutes_asleep} in additional_sleep increase within a week, starting from 2022-05-24?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_sleep AS (
    SELECT DATE(start_time) AS sleep_date, minutes_asleep
    FROM additional_sleep
    WHERE id = 'A4F_44160' AND DATE(start_time) BETWEEN '2022-05-24' AND '2022-05-30'
)
SELECT COUNT(*) AS consecutive_days
FROM (
    SELECT sleep_date, 
           minutes_asleep,
           @prev_minutes_asleep := IF(@prev_minutes_asleep IS NULL, minutes_asleep, @prev_minutes_asleep) AS prev_minutes_asleep,
           @is_increasing := IF(minutes_asleep > @prev_minutes_asleep, 1, 0) AS is_increasing,
           @prev_minutes_asleep := minutes_asleep
    FROM daily_sleep, (SELECT @prev_minutes_asleep := NULL, @is_increasing := 0) AS vars
    ORDER BY sleep_date
) AS subquery
WHERE is_increasing = 1;

